// Runs twice daily: 8:15am and 4:30pm
const categories = [
  { category: "general",  label: "Market" },
  { category: "forex",    label: "Macro/FX" },
  { category: "crypto",   label: "Crypto" },
  { category: "merger",   label: "M&A" },
];
return categories.map(c => ({ json: c }));

// Filter, deduplicate, and rank articles by institutional signal score
// Top MAX_ARTICLES selected by score, then re-sorted oldest-first for Discord display
const LOOKBACK_HRS  = 8;
const MAX_ARTICLES  = 6;

const SIGNAL_WEIGHTS = {
  'fed': 5, 'federal reserve': 5, 'fomc': 5, 'rate': 4, 'cpi': 4,
  'inflation': 4, 'gdp': 4, 'jobs': 4, 'nonfarm': 4, 'earnings': 3,
  'tariff': 4, 'recession': 4, 'sec': 3, 'merger': 3, 'acquisition': 3,
  'war': 3, 'sanctions': 3, 'oil': 2, 'opec': 2, 'dollar': 2,
  'bitcoin': 1, 'btc': 1, 'ethereum': 1, 'eth': 1, 'crypto': 1,
  'stablecoin': 1, 'coinbase': 0.5, 'binance': 0.5
};

const CRYPTO_KW = ['crypto','bitcoin','ethereum','blockchain','nft','defi'];
const isCryptoOnly = h => {
  const l = h.toLowerCase();
  return CRYPTO_KW.some(kw => l.includes(kw)) &&
    !h.match(/market|stock|index|fed|rate|earnings|sector/i);
};

const now    = Date.now() / 1000;
const cutoff = now - (LOOKBACK_HRS * 3600);
const seen   = new Set();

const articles = $input.all()
  .flatMap(i => Array.isArray(i.json) ? i.json : [i.json])
  .filter(a => a && a.datetime > cutoff && a.headline && a.headline.length > 20)
  .filter(a => !isCryptoOnly(a.headline))
  .filter(a => { if (seen.has(a.id)) return false; seen.add(a.id); return true; });

function score(a) {
  const txt = (a.headline + ' ' + (a.summary || '')).toLowerCase();
  let s = 0;
  for (const [kw, w] of Object.entries(SIGNAL_WEIGHTS)) if (txt.includes(kw)) s += w;
  return s;
}

// 1) Rank by signal score to pick the best MAX_ARTICLES
// 2) Re-sort those selected articles oldest-first for chronological Discord display
const sorted = articles
  .map(a => ({ ...a, _score: score(a) }))
  .sort((a, b) => b._score - a._score || b.datetime - a.datetime)
  .slice(0, MAX_ARTICLES)
  .sort((a, b) => a.datetime - b.datetime);  // oldest-first for display

return sorted.map(a => ({ json: a }));

