// Institutional Discord formatting
// Articles are already sorted oldest-first by Filter & Rank News
// Format: bold headline, backtick timestamp, source, blockquote AI summary, plain URL
const TIMEZONE = 'America/New_York';
const MAX      = 1950;

const originals = $('Filter & Rank News').all().map(i => i.json);
const aiTexts   = $input.all().map(i => (i.json.text || '').trim());

if (originals.length === 0) {
  return [{ json: { message: '\u{1F4F0} No significant financial news in the last 8 hours.' } }];
}

const now     = new Date();
const today   = now.toLocaleDateString('en-US', {
  weekday: 'long', month: 'long', day: 'numeric', year: 'numeric', timeZone: TIMEZONE
});
const runTime = now.toLocaleTimeString('en-US', {
  hour: '2-digit', minute: '2-digit', hour12: true, timeZone: TIMEZONE
});
const hour = parseInt(now.toLocaleString('en-US', {
  hour: 'numeric', hour12: false, timeZone: TIMEZONE
}));
const sessionLabel = hour >= 14 ? 'MARKET CLOSE  |  NEWS BRIEFING' : 'MARKET OPEN  |  NEWS BRIEFING';

// Discord-safe divider (30 chars)
const divider = '\u2550'.repeat(30);
const header  = `**${divider}**\n**\u{1F4F0}  ${sessionLabel}**\n_${today}  \u2022  ${runTime} ET_\n**${divider}**`;

const formatArticle = (a, aiSummary, idx) => {
  const time   = new Date(a.datetime * 1000).toLocaleTimeString('en-US', {
    hour: '2-digit', minute: '2-digit', hour12: true, timeZone: TIMEZONE
  });
  const source = a.source || '';
  const url    = a.url    || '';

  // Institutional block:
  // Bold numbered headline
  // Backtick timestamp + bullet + source (italic)
  // Blockquote AI analysis
  // Plain URL on own line
  let block = `\n**${idx}. ${a.headline}**\n`;
  block    += `\`${time} ET\`  \u2022  _${source}_\n`;
  if (aiSummary) block += `> \u{1F4CA} ${aiSummary}\n`;
  if (url)       block += `[\u2197 Read Article](${url})`;
  return block;
};

// Smart chunking — never exceed MAX chars per message
const messages = [];
let chunk = header;

originals.forEach((a, i) => {
  const article   = formatArticle(a, aiTexts[i] || '', i + 1);
  const candidate = chunk + '\n' + article;
  if (candidate.length > MAX && chunk !== header) {
    messages.push(chunk);
    chunk = header + '\n' + article;
  } else {
    chunk = candidate;
  }
});
if (chunk !== header) messages.push(chunk);

return messages.map(msg => ({ json: { message: msg } }));

// Pairs AI summaries with original articles for storage
// Runs in the Discord chain (twice daily) — the only time AI summaries exist
// 15-min logging chain does NOT include ai_summary, so upserts here are never overwritten
const TIMEZONE = 'America/New_York';
const originals = $('Filter & Rank News').all().map(i => i.json);
const aiTexts   = $input.all().map(i => (i.json.text || '').trim());

if (originals.length === 0) return [];

const TOPICS = [
  { tag: 'Fed/Rates',    re: /\b(fed|federal reserve|fomc|interest rate|rate hike|rate cut|jerome powell|inflation|cpi|pce|bls|jobs report|nonfarm|unemployment)\b/i },
  { tag: 'Earnings',     re: /\b(earnings|revenue|profit|eps|guidance|quarterly results|beats|misses|q[1-4] 20\d\d)\b/i },
  { tag: 'Energy',       re: /\b(oil|crude|wti|brent|opec|natural gas|lng|energy|gasoline|petroleum)\b/i },
  { tag: 'Geopolitical', re: /\b(war|sanction|tariff|trade war|military|attack|invasion|drone|nato|china|russia|iran|north korea|taiwan|ukraine|middle east|israel|conflict)\b/i },
  { tag: 'Crypto',       re: /\b(bitcoin|btc|ethereum|eth|crypto|blockchain|defi|altcoin|stablecoin|coinbase|binance|solana|xrp)\b/i },
  { tag: 'FX/Macro',     re: /\b(dollar|euro|yen|pound|cny|yuan|fx|forex|currency|gdp|recession|ecb|boe|boj|imf|world bank)\b/i },
  { tag: 'M&A',          re: /\b(merger|acquisition|takeover|buyout|deal|acquire|acquired|purchase agreement|private equity)\b/i },
  { tag: 'Tech',         re: /\b(ai|artificial intelligence|microsoft|google|apple|amazon|nvidia|meta|openai|semiconductor|chip|ipo|startup)\b/i },
  { tag: 'Markets',      re: /\b(s&p|nasdaq|dow|stock|rally|selloff|sell.off|correction|bull|bear|equity|shares|index)\b/i },
];
function getTopic(h) {
  for (const t of TOPICS) if (t.re.test(h || '')) return t.tag;
  return 'General';
}
function cleanSummary(raw) {
  if (!raw) return '';
  return raw.replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/&amp;/g,'&')
    .replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#39;/g,"'")
    .replace(/\s+/g,' ').trim().substring(0, 300);
}

return originals.map((a, idx) => {
  const dt      = new Date(a.datetime * 1000);
  const dateStr = dt.toLocaleDateString('en-US', { year:'numeric', month:'2-digit', day:'2-digit', timeZone: TIMEZONE });
  const timeStr = dt.toLocaleTimeString('en-US', { hour:'2-digit', minute:'2-digit', hour12:true, timeZone: TIMEZONE });
  const localISO = dt.toLocaleString('sv-SE', { timeZone: TIMEZONE }).replace(' ','T');
  return { json: {
    timestamp:  localISO,
    date:       dateStr,
    time:       timeStr,
    topic:      getTopic(a.headline),
    headline:   a.headline   || '',
    summary:    cleanSummary(a.summary),
    ai_summary: aiTexts[idx] || '',
    source:     a.source     || '',
    url:        a.url        || '',
    article_id: String(a.id  || ''),
  }};
});

const categories = [
  { category: 'general', label: 'Market' },
  { category: 'forex',   label: 'Macro/FX' },
  { category: 'crypto',  label: 'Crypto' },
  { category: 'merger',  label: 'M&A' },
];
return categories.map(c => ({ json: c }));

const allItems = $input.all();
const catItems = $('Log Categories').all();
const results  = [];

const TOPICS = [
  { tag: 'Fed/Rates',    re: /\b(fed|federal reserve|fomc|interest rate|rate hike|rate cut|jerome powell|inflation|cpi|pce|bls|jobs report|nonfarm|unemployment)\b/i },
  { tag: 'Earnings',     re: /\b(earnings|revenue|profit|eps|guidance|quarterly results|beats|misses|q[1-4] 20\d\d)\b/i },
  { tag: 'Energy',       re: /\b(oil|crude|wti|brent|opec|natural gas|lng|energy|gasoline|petroleum)\b/i },
  { tag: 'Geopolitical', re: /\b(war|sanction|tariff|trade war|military|attack|invasion|drone|nato|china|russia|iran|north korea|taiwan|ukraine|middle east|israel|conflict)\b/i },
  { tag: 'Crypto',       re: /\b(bitcoin|btc|ethereum|eth|crypto|blockchain|defi|altcoin|stablecoin|coinbase|binance|solana|xrp)\b/i },
  { tag: 'FX/Macro',     re: /\b(dollar|euro|yen|pound|cny|yuan|fx|forex|currency|gdp|recession|ecb|boe|boj|imf|world bank)\b/i },
  { tag: 'M&A',          re: /\b(merger|acquisition|takeover|buyout|deal|acquire|acquired|purchase agreement|private equity)\b/i },
  { tag: 'Tech',         re: /\b(ai|artificial intelligence|microsoft|google|apple|amazon|nvidia|meta|openai|semiconductor|chip|ipo|startup)\b/i },
  { tag: 'Markets',      re: /\b(s&p|nasdaq|dow|stock|rally|selloff|sell.off|correction|bull|bear|equity|shares|index)\b/i },
];

function getTopic(headline, baseCategory) {
  for (const t of TOPICS) if (t.re.test(headline || '')) return t.tag;
  const fallbacks = { general: 'Markets', forex: 'FX/Macro', crypto: 'Crypto', merger: 'M&A' };
  return fallbacks[baseCategory] || 'General';
}

for (let i = 0; i < allItems.length; i++) {
  const item     = allItems[i];
  const articles = Array.isArray(item.json) ? item.json : [item.json];
  const pairedIdx = (item.pairedItem && typeof item.pairedItem === 'object') ? item.pairedItem.item : i;
  const catItem  = catItems[pairedIdx] || catItems[i % catItems.length];
  const category = catItem ? catItem.json.category : 'general';
  for (const a of articles) {
    if (!a || !a.headline) continue;
    results.push({ json: { ...a, category, topic: getTopic(a.headline, category) } });
  }
}
return results;

// Log raw articles to Google Sheets + PostgreSQL every 15 min
// ai_summary intentionally excluded — only the twice-daily Discord chain writes that field
// so upserts here never overwrite AI summaries already stored by the Discord chain
const TIMEZONE     = 'America/New_York';
const LOOKBACK_HRS = 2;
const now    = Date.now() / 1000;
const cutoff = now - (LOOKBACK_HRS * 3600);
const seen   = new Set();

const articles = $input.all()
  .map(i => i.json)
  .filter(a => a && a.datetime && a.datetime > cutoff && a.headline && a.headline.length > 20)
  .filter(a => { const k = String(a.id || a.headline); if (seen.has(k)) return false; seen.add(k); return true; })
  .sort((a, b) => b.datetime - a.datetime)
  .slice(0, 5);

if (articles.length === 0) return [];

function cleanSummary(raw) {
  if (!raw) return '';
  return raw.replace(/<[^>]+>/g,' ').replace(/&nbsp;/g,' ').replace(/&amp;/g,'&')
    .replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#39;/g,"'")
    .replace(/\s+/g,' ').trim().substring(0, 300);
}

return articles.map(a => {
  const dt = new Date(a.datetime * 1000);
  const dateStr = dt.toLocaleDateString('en-US', { year:'numeric', month:'2-digit', day:'2-digit', timeZone: TIMEZONE });
  const timeStr = dt.toLocaleTimeString('en-US', { hour:'2-digit', minute:'2-digit', hour12:true, timeZone: TIMEZONE });
  const localISO = dt.toLocaleString('sv-SE', { timeZone: TIMEZONE }).replace(' ','T');
  return { json: {
    timestamp:  localISO,
    date:       dateStr,
    time:       timeStr,
    category:   a.category   || '',
    topic:      a.topic      || '',
    headline:   a.headline   || '',
    summary:    cleanSummary(a.summary),
    source:     a.source     || '',
    url:        a.url        || '',
    article_id: String(a.id  || ''),
  }};
});

// Prep raw articles for PostgreSQL upsert (no ai_summary — Discord chain handles that)
return $input.all().map(item => {
  const a = item.json;
  return { json: {
    article_id: a.article_id || '',
    timestamp:  a.timestamp  || new Date().toISOString(),
    date:       a.date       || null,
    time:       a.time       || null,
    category:   a.category   || null,
    topic:      a.topic      || null,
    headline:   a.headline   || null,
    summary:    a.summary    || null,
    source:     a.source     || null,
    url:        a.url        || null,
  }};
});
